import * as vscode from 'vscode';
import { parseDita } from '../parser/ditaParser';
import { renderDocument } from '../render/renderer';
import { readFileSync } from 'fs';
import { dirname, join } from 'path';

function getStylesCss(context: vscode.ExtensionContext): string {
  const stylePath = join(context.extensionPath, 'media', 'styles.css');
  try {
    return readFileSync(stylePath, 'utf-8');
  } catch {
    return '';
  }
}

function getWebviewScript(): string {
  return `
(function() {
  document.addEventListener('click', function(e) {
    var target = e.target;
    var anchor = target.closest ? target.closest('a') : null;
    if (!anchor) return;
    var href = anchor.getAttribute('href');
    if (!href || href.charAt(0) !== '#') return;
    e.preventDefault();
    var id = href.slice(1);
    var el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
  });
})();
`;
}

export class DitaViewerProvider implements vscode.CustomTextEditorProvider {
  constructor(private readonly context: vscode.ExtensionContext) {}

  async resolveCustomTextEditor(
    document: vscode.TextDocument,
    webviewPanel: vscode.WebviewPanel,
    _token: vscode.CancellationToken,
  ): Promise<void> {
    webviewPanel.webview.options = {
      enableScripts: true,
      localResourceRoots: [vscode.Uri.file(this.context.extensionPath)],
    };

    const updateWebview = () => {
      const html = this.generateHtml(document, webviewPanel.webview);
      webviewPanel.webview.html = html;
    };

    updateWebview();

    const changeSubscription = vscode.workspace.onDidChangeTextDocument((e) => {
      if (e.document.uri.toString() === document.uri.toString()) {
        updateWebview();
      }
    });

    webviewPanel.onDidDispose(() => {
      changeSubscription.dispose();
    });
  }

  private generateHtml(
    document: vscode.TextDocument,
    webview: vscode.Webview,
  ): string {
    const css = getStylesCss(this.context);
    const script = getWebviewScript();
    const stylesUri = webview.asWebviewUri(
      vscode.Uri.file(join(this.context.extensionPath, 'media', 'styles.css')),
    );

    const documentDir = dirname(document.uri.fsPath);

    const asWebviewUri = (relPath: string): string => {
      const fullPath = join(documentDir, relPath);
      const fileUri = vscode.Uri.file(fullPath);
      return webview.asWebviewUri(fileUri).toString();
    };

    try {
      const ditaDoc = parseDita(document.getText());
      const content = renderDocument(ditaDoc.root, {
        headingLevel: 1,
        asWebviewUri,
        documentDir,
      });

      return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<meta http-equiv="Content-Security-Policy" content="default-src 'none'; img-src ${webview.cspSource} https:; style-src ${webview.cspSource} 'unsafe-inline'; script-src 'unsafe-inline';">
<link rel="stylesheet" href="${stylesUri}">
<title>${document.fileName}</title>
</head>
<body>
${content}
<script>${script}</script>
</body>
</html>`;
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      return `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><title>Error</title></head>
<body>
<div style="padding:2rem;color:#c0392b;">
<h2>Render Error</h2>
<pre>${escapeHtml(message)}</pre>
</div>
</body>
</html>`;
    }
  }
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}
